export function serveStatic(pathname) {
  let p = pathname;
  if (p === "/" || p === "") p = "/index.html";
  const f = STATIC_FILES.get(p);
  if (!f) return null;
  return new Response(f.body, { headers: { "Content-Type": f.ct, "Cache-Control": "public, max-age=3600" } });
}
